import math
import numpy as np
from scipy.optimize import fsolve

def poly(xs: list, x: float):
    """
    Evaluates polynomial with coefficients xs at point x.
    return xs[0] + xs[1] * x + xs[2] * x^2 + .... xs[n] * x^n
    """
    return sum([coeff * math.pow(x, i) for i, coeff in enumerate(xs)])

def find_zero(xs: list):
    """ xs are coefficients of a polynomial.
    find_zero find x such that poly(x) = 0.
    find_zero returns only only zero point, even if there are many.
    Moreover, find_zero only takes list xs having even number of coefficients
    and largest non zero coefficient as it guarantees
    a solution.
    """
    if len(xs) % 2 != 0:
        raise ValueError("The list of coefficients must have an even number of elements.")
    if max(xs) == 0 and min(xs) == 0:
        raise ValueError("The list of coefficients must have at least one non-zero element.")

    def func(x):
        return poly(xs, x)

    # Initial guess for the root
    if len(xs) == 2:
        x0 = -xs[0] / xs[1]
    else:
        # For higher degree polynomials, try to find a better initial guess
        x0 = np.roots(xs)[0].real

    try:
        return fsolve(func, x0)[0]
    except Exception as e:
        raise ValueError("Failed to find a root for the given polynomial.") from e
